import { useState } from "react";
import Sidebar from "../components/Sidebar";
import KnowledgeBaseForm from "../components/KnowledgeBaseForm";
import BannedPhrasesManager from "../components/BannedPhrasesManager";
import ActionTypesManager from "../components/ActionTypesManager";
import AgentActionsFeed from "../components/AgentActionsFeed";
import FlagsFeed from "../components/FlagsFeed";

const TABS = [
  { id: "kb", label: "Knowledge Base" },
  { id: "phrases", label: "Banned Phrases" },
  { id: "actions", label: "Action Types" },
  { id: "feeds", label: "Live Feeds" },
];

export default function TeamLeadDashboard() {
  const [activeTab, setActiveTab] = useState("kb");

  return (
    <div className="min-h-screen bg-mission-bg flex">
      <Sidebar />

      <main className="flex-1 ml-[260px] p-8 md:p-10">
        <div className="max-w-6xl mx-auto">
          <header className="mb-10">
            <h1 className="font-display text-[32px] leading-[40px] font-semibold text-text-main mb-2">
              Operations Center
            </h1>
            <p className="text-text-muted text-base">
              System status, live flags, and knowledge base administration.
            </p>
          </header>

          <section className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
            <div className="lg:col-span-2 bg-mission-surface p-6 md:p-8 rounded-enterprise shadow-soft-dark border border-mission-border">
              <h2 className="font-display text-[20px] font-semibold text-text-main mb-2">
                Knowledge Base
              </h2>
              <p className="text-text-muted mb-6 text-sm">Manage active policies and procedures.</p>
              <button
                type="button"
                onClick={() => setActiveTab("kb")}
                className="bg-accent-violet hover:bg-opacity-80 text-white font-medium py-3 px-6 rounded-enterprise transition-colors border border-transparent"
              >
                + Deploy New Policy
              </button>
            </div>

            <div className="bg-mission-surface p-6 md:p-8 rounded-enterprise shadow-soft-dark border border-mission-border">
              <h2 className="font-display text-sm font-medium text-text-main mb-4 uppercase tracking-wider">
                System Health
              </h2>
              <div className="flex items-center justify-between p-4 bg-mission-bg border border-mission-border rounded-enterprise mb-3">
                <span className="text-sm font-medium text-text-muted">Active Alerts</span>
                <div className="font-mono text-accent-coral font-semibold text-lg">
                  04
                </div>
              </div>
              <div className="flex items-center justify-between p-4 bg-mission-bg border border-mission-border rounded-enterprise">
                <span className="text-sm font-medium text-text-muted">Control Modules</span>
                <div className="font-mono text-accent-cyan font-semibold text-lg">
                  {String(TABS.length).padStart(2, "0")}
                </div>
              </div>
            </div>
          </section>

          <div className="flex flex-wrap gap-2 mb-6 p-1.5 bg-mission-surface rounded-enterprise shadow-soft-dark border border-mission-border">
            {TABS.map((tab) => (
              <button
                key={tab.id}
                type="button"
                onClick={() => setActiveTab(tab.id)}
                className={`tab-btn ${
                  activeTab === tab.id ? "tab-btn-active" : "tab-btn-inactive"
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>

          {activeTab === "kb" && <KnowledgeBaseForm />}
          {activeTab === "phrases" && <BannedPhrasesManager />}
          {activeTab === "actions" && <ActionTypesManager />}
          {activeTab === "feeds" && (
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
              <FlagsFeed />
              <AgentActionsFeed />
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
